import groovy.json.JsonOutput
def user = event.getRequesteeObject()
def oid = user.getOid()
def nombre = (user.getFullName() != null) ? user.getFullName().getOrig() : user.getName().getOrig()
def correo = (user.getEmailAddress() != null) ? user.getEmailAddress() : ''
return JsonOutput.toJson([ oid: oid, nombre: nombre, correo: correo ])

import java.net.http.HttpClient
import java.net.http.HttpRequest
import java.net.http.HttpResponse
import java.net.URI
import java.time.Duration

def cuerpo = message.getBody()
def client = HttpClient.newBuilder().connectTimeout(Duration.ofSeconds(10)).build()
def request = HttpRequest.newBuilder()
    .uri(URI.create('http://telesecure_webhook:5000/provision'))
    .timeout(Duration.ofSeconds(120))
    .header('Content-Type', 'application/json')
    .header('X-Auth-Token', 'e228111abf729700c4934bc2b7e36701b5fc8859419619a5')
    .POST(HttpRequest.BodyPublishers.ofString(cuerpo))
    .build()
def response = client.send(request, HttpResponse.BodyHandlers.ofString())
LOGGER.info('TeleSecure webhook HTTP {} -> {}', response.statusCode(), response.body())
if (response.statusCode() >= 400) {
    throw new RuntimeException('Webhook error HTTP ' + response.statusCode() + ': ' + response.body())
}
